<script>
import {
    locateBillingService
} from "../../../services/locateBillingService";
import DataService from "../../../services/DataService";
import Schema from "./TicketLogSchema";
import VerticalFlowChartModel from '../../../components/Modals/VerticalFlowChartModel.vue';

export default {
    name: "TicketLog",
    components: {
        VerticalFlowChartModel
    },
    data() {
        return {
            isLoading: false,
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            LegendArray: [],
            SortBy: '',
            SortExp: '',
            CurrentPage: 1,
            TotalRecords: 0,
            ListingData: [],
            Buttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            Headers: Schema.headerSchema,
            searchCondition: "",
            selectedClientId: null,
            expandedRows: {},
            childRows: {},
            IsViewTicket: false,
            TicketContent: '',
            TicketNumber: '',
            TransmissionId: '',
            ActivityId: '',
            activeTab: 'OldProcessLog',
            processLogData: null,
            newProcessLogData: [],
            IsChildData: false,
            TicketActivityContent: [],
            ConfigurationId: '',
            modelopen: false,
            isBillingType: false,
            modeltype: 'Ticketlog',
            isShown:false,
            isShownProcessedTicket:false
        }
    },
     mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    created: function () {
        var vm = this;
         var UserDateFormat= vm.GetUserInfo.DateFormat == ""? 'MM/DD/YYYY' : vm.GetUserInfo.DateFormat;
        vm.Headers.forEach(element => {
            element.DISPLAY_NAME = vm.$t(element.DISPLAY_NAME);
        });
        if (vm.leftSearchFields ?.length > 0) {
            vm.leftSearchFields[1].onChange = vm.onSelectionChange;
            vm.leftSearchFields.find(f => f.fieldName === 'Work_Date').format= UserDateFormat;
            vm.leftSearchFields.find(f => f.fieldName === 'ProcessDate').format= UserDateFormat;
            vm.leftSearchFields.find(f => f.fieldName === 'Work_Date').onChange= vm.setTimerDate;
            vm.leftSearchFields.find(f => f.fieldName === 'ProcessDate').onChange= vm.setProcessTimerDate;
        }
        Schema.bindleftCommonSearchdropdown(this);
        vm.fetchclientlist();
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        //vm.FetchTicketLog();
    },
    methods: {
        setTimerDate(x) {
            this.applySecondDate(x);
        },

        setProcessTimerDate(x) {
            this.applySecondDate(x);
        },
       applySecondDate(x) {
            var vm = this;
            x.datePickerConfig.maxDate = '';

            const today = new Date();
            today.setHours(0, 0, 0, 0);

            const parseDate = (val) => {
                if (val instanceof Date && !isNaN(val.getTime())) {
                    const d = new Date(val);
                    d.setHours(0, 0, 0, 0);
                    return d;
                }

                if (typeof val === 'string' && val) {
                    const parts = val.split(/[\/\-]/);
                    if (parts.length === 3) {
                        const month = parseInt(parts[0], 10) - 1;
                        const day   = parseInt(parts[1], 10);
                        const year  = parseInt(parts[2], 10);

                        const d = new Date(year, month, day);
                        d.setHours(0, 0, 0, 0);
                        return isNaN(d.getTime()) ? null : d;
                    }
                }
                return null;
            };

            const valueDate  = parseDate(x.value);
            const secondDate = parseDate(x.secondValue);

            // ✅ If secondValue already exists
            if (secondDate) {
                if (valueDate && valueDate > secondDate) {
                    x.secondValue = vm.$options.filters.formatDate(valueDate);
                }else{
                    x.secondValue = vm.$options.filters.formatDate(secondDate);
                }
                // else → keep existing secondValue
                return;
            }

            // ✅ If secondValue does NOT exist yet
            if (valueDate && valueDate > today) {
                x.secondValue = vm.$options.filters.formatDate(valueDate);
            } else {
                x.secondValue = vm.$options.filters.formatDate(today);
            }
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson;
                } else {
                    this.searchCondition = value.searchCondition || "";
                }
            } else {
                this.searchCondition = "";
            }
            if (this.searchCondition) {
                this.searchCondition = this.searchCondition.replace(/WorkDate=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    return `workDateFrom=${from}&workDateTo=${to}`;
                });
                this.searchCondition = this.searchCondition.replace(/ProcessDate=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    return `processDateFrom=${from}&processDateTo=${to}`;
                });
            }
            this.FetchTicketLog();
        },
        fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = vm.clientList;
                vm.groupedUtilities = vm.clientList;
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = [];
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = [];
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'TicketImage':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchTicketLog();
        },
        actionButtonClick: function (callbackfunction, item, event) {
            switch (callbackfunction) {
                case 'ViewTicketImage':
                    this.viewTicketImage(item);
                    break;
                    case 'clkViewDetail':
                    this.toggleExpandRow(item, event);
                    break;
            }
        },
        commonHeaderButtonClick: function (event) {
            // Handle header button clicks if needed
        },
        getFlagClass(flag) {
            if (!flag) return '';
            const flagUpper = flag.toUpperCase().trim();
            if (flagUpper === 'UNPROCESSED') {
                return 'bg-danger py-1 px-1 text-white w-100 d-block text-center';
            } else if (flagUpper === 'BANKED') {
                return 'bg-warning py-1 px-1 text-white w-100 d-block text-center';
            } else if (flagUpper === 'PROCESSED') {
                return 'bg-success py-1 px-1 text-white w-100 d-block text-center';
            }
            else if (flagUpper === 'SUPPRESSED') {
                return 'bg-secondary py-1 px-1 text-center w-100 text-white d-block';
            }
            else if (flagUpper === 'DONOTBILL') {
                 return 'bg-danger py-1 px-1 text-white w-100 d-block text-center';
            }
            return '';
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            if (this.SortExp == "") {
                this.SortExp = "ASC";
            } else if (this.SortExp == "ASC") {
                this.SortExp = "DESC";
            } else {
                this.SortExp = "ASC";
            }
            this.FetchTicketLog();
        },
        FetchTicketLog: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}`;

            // Add search condition if available
            if (vm.searchCondition) {
                url += `&${vm.searchCondition}`;
            }

            locateBillingService.GetTicketLog(url).then((response) => {
                vm.isLoading = false;
                if (response.data.result) {
                    vm.ListingData = JSON.parse(response.data.result)
                }
                if (vm.ListingData && vm.ListingData.length > 0) {
                    vm.ListingData.forEach((item) => {
                        if (item.WORK_DATE) {
                            item.WORK_DATE = new Date(item.WORK_DATE);
                        }
                        if (item.PROCESS_DATE) {
                            item.PROCESS_DATE = new Date(item.PROCESS_DATE);
                        }
                    });
                    vm.TotalRecords = vm.ListingData[0].TOTAL_RECORDS || vm.ListingData[0].TOTALRECORDS || 0;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                } else {
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            }).catch((error) => {
                vm.isLoading = false;
                vm.ListingData = [];
                vm.TotalRecords = 0;
                console.error('Error fetching ticket log:', error);
            });
        },
        toggleExpandRow: async function (item, event) {
            var vm = this;
            var privilegeParams = `controller=TicketLog&action=ChildTicketLog`;
            await DataService.CheckPrivilege(privilegeParams).then(async function (response) {
            if (response.data) {
            vm.isLoading=true;
            vm.processLogData=null;
            vm.newProcessLogData=[];
            vm.TicketActivityContent= [];
            vm.TicketNumber='';
            vm.ActivityId='';
            vm.TicketNumber = item.TICKETNUMBER;
            vm.ActivityId = item.ACTIVITY_ID;
            vm.IsChildData = !vm.IsChildData;
            var url = `TicketNumber=${vm.TicketNumber}&ActivityId=${vm.ActivityId}&workDateFrom=&workDateTo=`
            await locateBillingService.ChildTicketLog(url).then((response) => {
                if (response.data.length > 0) {
                    vm.TicketActivityContent = response.data;
                    vm.processLogData = response.data.find(x => x.TYPE === 'PROCESSLOG') || null;
                }
            });
            // Load new process log data
            var urlNew = `ticketNumber=${vm.TicketNumber}&activityId=${vm.ActivityId}&workDateFrom=&workDateTo=`;
            await locateBillingService.ChildTicketLogNew(urlNew).then((response) => {
                if (response.data && response.data.length > 0) {
                    vm.newProcessLogData = response.data;
                }
            });
            vm.isLoading=false;
             vm.$nextTick(() => {
                        setTimeout(() => {
                            vm.isShownProcessedTicket = true;  
                }, 50);
            });
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        CloseChildRow: function () {
            var vueObj = this;
            vueObj.activeTab = 'OldProcessLog';
            vueObj.IsChildData = false;
            vueObj.isShownProcessedTicket=false;
        },
        getWorkDateFrom() {
            var workDateField = this.leftSearchFields.find(f => f.fieldName === 'WorkDate');
            return workDateField && workDateField.value ? workDateField.value.from : '';
        },
        getWorkDateTo() {
            var workDateField = this.leftSearchFields.find(f => f.fieldName === 'WorkDate');
            return workDateField && workDateField.value ? workDateField.value.to : '';
        },
        viewTicketImage: async function (item) {
            var vm = this;
            vm.TicketNumber = item.TICKETNUMBER;
            vm.TransmissionId = item.TRANSMISSION_ID;
            vm.IsViewTicket = !vm.IsViewTicket;
            var url = `TicketNumber=${vm.TicketNumber}&TransmissionId=${vm.TransmissionId}`
            await locateBillingService.ViewTicketImage(url).then((response) => {
                if (response.data.length > 0) {
                    vm.TicketContent = response.data[0].RAW_IMAGE;
                }
            });
        },
        CloseTemplate: function () {
            var vueObj = this;
            vueObj.IsViewTicket = false;
        },
        viewBillingFlowchart(data) {
            var vm = this;
            if (data.CONFIGURATION_ID > 0) {
                vm.modelDetail = data;
                vm.modelopen = true;
            }
        },
        onSelectionChange(value, x) {
            // Load utilities when client selection changes
            var vm = this;
            //vm.isLoading = true;
            vm.selectedClientId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                //vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = SelectedUtilityList;
                }
            }).catch(error => {
                //vm.isLoading = false;
                vm.UtilityList = [];
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').value = '';
            }).finally(() => {
                //vm.isLoading = false;
            });
        }
    }
}
</script>

